import type {
    ThemeAccentColors,
    ThemeDefinition,
    ThemeFeedbackColors,
    ThemePrimaryColors,
    ThemeSyntaxColors,
} from "../../types/theme.ts";
import { themeKeyMetaMap } from "../../types/themes.ts";
import { oklch } from "../../utils/color.ts";

import createPalette from "./create-palette-light.ts";
import createSyntax from "./create-syntax-light.ts";
import createUi from "./create-ui-light.ts";

const meta = themeKeyMetaMap["black-atom-mnml-orange-light"];

const primaries: ThemePrimaryColors = {
    d10: oklch(0.20, 0.01, 220),
    d20: oklch(0.28, 0.01, 220),
    d30: oklch(0.36, 0.01, 220),
    d40: oklch(0.42, 0.01, 220),

    m10: oklch(0.48, 0.01, 220),
    m20: oklch(0.58, 0.01, 220),
    m30: oklch(0.64, 0.01, 220),
    m40: oklch(0.72, 0.01, 220),

    l10: oklch(0.94, 0.01, 220),
    l20: oklch(0.96, 0.01, 220),
    l30: oklch(0.98, 0.01, 220),
    l40: oklch(1.00, 0.01, 220),
};

const accents: ThemeAccentColors = {
    a10: oklch(0.7506, 0.175, 60.0),
    a20: oklch(0.66, 0.185, 250.0),
    a30: oklch(0.70, 0.185, 40.0),
};

const palette = createPalette(primaries, {
    debug: false,
    override: (palette) => ({
        ...palette,
        yellow: accents.a10,
        darkYellow: accents.a20,
    }),
});

const feedback: ThemeFeedbackColors = {
    info: oklch(0.65, 0.15, 250),
    warning: accents.a10,
    negative: accents.a20,
    success: oklch(0.65, 0.15, 150),
};

const options = { primaries, palette, feedback, accents };
const ui = createUi(options);
const syntax: ThemeSyntaxColors = {
    ...createSyntax(options),
    keyword: {
        default: accents.a20,
        import: accents.a30 ?? accents.a20,
        export: accents.a30 ?? accents.a20,
    },
};

const theme: ThemeDefinition = {
    meta,
    primaries,
    palette,
    ui,
    syntax,
};

export default theme;

import type { ThemeCreatorOptions, ThemeUiColors } from "../../types/theme.ts";
import { tint } from "../../utils/color.ts";

export default function (
    { primaries, feedback, accents }: ThemeCreatorOptions,
): ThemeUiColors {
    function t(color: string) {
        return tint({ color, with: primaries.l40 });
    }

    const sharedFg = {
        negative: feedback.negative,
        info: feedback.info,
        hint: feedback.warning,
        warn: feedback.warning,
        positive: feedback.success,
        add: feedback.success,
        delete: feedback.negative,
        modify: feedback.info,
    };

    const sharedBg = {
        negative: t(feedback.negative),
        info: t(feedback.info),
        hint: t(feedback.warning),
        warn: t(feedback.warning),
        positive: t(feedback.success),
        add: t(feedback.success),
        delete: t(feedback.negative),
        modify: t(feedback.info),
    };

    return {
        bg: {
            default: primaries.l30,
            panel: primaries.l20,
            float: primaries.l20,
            active: primaries.l40,
            disabled: primaries.l10,
            hover: primaries.l20,
            selection: primaries.l10,
            search: primaries.l10,
            contrast: primaries.d40,
            ...sharedBg,
        },
        fg: {
            default: primaries.d20,
            subtle: primaries.m10,
            accent: accents.a10,
            disabled: primaries.m30,
            contrast: primaries.l20,
            ...sharedFg,
        },
    };
}

