import { tint, oklch } from "/Users/brunner/repos/black-atom-industries/core/src/utils/color.ts";

function lum(hex: string): number {
  const [r, g, b] = (hex.match(/[0-9a-f]{2}/gi) ?? []).map(x => {
    const c = parseInt(x, 16) / 255;
    return c <= 0.04045 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4);
  });
  return 0.2126 * r + 0.7152 * g + 0.0722 * b;
}
function ratio(a: string, b: string): number {
  const la = lum(a), lb = lum(b);
  return (Math.max(la, lb) + 0.05) / (Math.min(la, lb) + 0.05);
}

type ThemeInfo = { name: string; d10: string; feedback: Record<string, { fg: string; label: string }> };
const themes: ThemeInfo[] = [
  { name: "default-dark-dimmed", d10: oklch(0.12, 0.008, 170),
    feedback: { negative: { fg: "#e97292", label: "neg" }, info: { fg: "#00b9c3", label: "info" }, positive: { fg: "#4cb86a", label: "pos" } } },
  { name: "default-dark", d10: oklch(0.08, 0.005, 170),
    feedback: { negative: { fg: "#e97292", label: "neg" }, info: { fg: "#00b9c3", label: "info" }, positive: { fg: "#4cb86a", label: "pos" } } },
  { name: "orange-dark", d10: oklch(0.08, 0.01, 220),
    feedback: { negative: { fg: "#ff7a46", label: "neg" }, info: { fg: "#3a93e6", label: "info" }, positive: { fg: "#3aa85b", label: "pos" } } },
];

for (const t of themes) {
  console.log(`\n=== ${t.name} (d10=${t.d10}) ===`);
  console.log("Amount | token | bg        | vs default | vs fg");
  console.log("-------|-------|-----------|------------|-------");
  for (const amount of [0.25, 0.30, 0.35, 0.40, 0.45, 0.50]) {
    for (const [key, fb] of Object.entries(t.feedback)) {
      const bg = tint({ color: fb.fg, with: t.d10, amount });
      const rDef = ratio(t.d10, bg).toFixed(2);
      const rFg = ratio(bg, fb.fg).toFixed(2);
      console.log(`${amount.toFixed(2)}  | ${fb.label}    | ${bg} | ${rDef}:1    | ${rFg}:1`);
    }
  }
}

